-- ======================================================
-- Clinica SaludTotal - Database Seed Script
-- Generated for PostgreSQL
-- Execute: psql -U postgres -d clinica -f db_seed.sql
-- ======================================================

-- Drop tables (children first, then parents)
DROP TABLE IF EXISTS frames_autenticacion_facial CASCADE;
DROP TABLE IF EXISTS intentos_autenticacion_facial CASCADE;
DROP TABLE IF EXISTS pacientes CASCADE;
DROP TABLE IF EXISTS doctores CASCADE;
DROP TABLE IF EXISTS sesiones_autenticacion_facial CASCADE;
DROP TABLE IF EXISTS perfiles_faciales CASCADE;
DROP TABLE IF EXISTS usuarios CASCADE;

CREATE TABLE usuarios (
    id INTEGER DEFAULT nextval('usuarios_id_seq'::regclass) NOT NULL,
    email VARCHAR(150) NOT NULL,
    password_hash VARCHAR(255) NOT NULL,
    nombre VARCHAR(100) NOT NULL,
    apellido VARCHAR(100) NOT NULL,
    telefono VARCHAR(20),
    rol VARCHAR(50) NOT NULL,
    activo BOOLEAN,
    fecha_creacion TIMESTAMP,
    ultimo_acceso TIMESTAMP,
    login_facial_habilitado BOOLEAN,
    ultimo_login_facial TIMESTAMP,
    CONSTRAINT usuarios_rol_check CHECK ((((rol)::text = ANY ((ARRAY['admin'::character varying, 'doctor'::character varying, 'recepcionista'::character varying, 'paciente'::character varying])::text[])))),
    CONSTRAINT usuarios_pkey PRIMARY KEY (id)
);

CREATE TABLE perfiles_faciales (
    id BIGINT DEFAULT nextval('perfiles_faciales_id_seq'::regclass) NOT NULL,
    usuario_id INTEGER NOT NULL,
    embedding_json TEXT NOT NULL,
    imagen_referencia TEXT,
    algoritmo VARCHAR(100),
    version_modelo VARCHAR(50),
    activo BOOLEAN,
    fecha_registro TIMESTAMP DEFAULT now(),
    fecha_actualizacion TIMESTAMP DEFAULT now(),
    CONSTRAINT perfiles_faciales_pkey PRIMARY KEY (id),
    CONSTRAINT perfiles_faciales_usuario_id_key UNIQUE (usuario_id),
    CONSTRAINT perfiles_faciales_usuario_id_fkey FOREIGN KEY (usuario_id) REFERENCES usuarios(id) ON DELETE CASCADE
);

CREATE TABLE sesiones_autenticacion_facial (
    id BIGINT DEFAULT nextval('sesiones_autenticacion_facial_id_seq'::regclass) NOT NULL,
    session_token VARCHAR(120) NOT NULL,
    usuario_id INTEGER,
    challenge_type VARCHAR(30) NOT NULL,
    challenge_descripcion VARCHAR(255),
    estado VARCHAR(20) NOT NULL,
    ip_cliente VARCHAR(50),
    user_agent TEXT,
    fecha_creacion TIMESTAMP DEFAULT now(),
    fecha_expiracion TIMESTAMP NOT NULL,
    fecha_uso TIMESTAMP,
    CONSTRAINT sesiones_autenticacion_facial_pkey PRIMARY KEY (id),
    CONSTRAINT sesiones_autenticacion_facial_session_token_key UNIQUE (session_token),
    CONSTRAINT sesiones_autenticacion_facial_usuario_id_fkey FOREIGN KEY (usuario_id) REFERENCES usuarios(id) ON DELETE SET NULL
);

CREATE TABLE doctores (
    id INTEGER DEFAULT nextval('doctores_id_seq'::regclass) NOT NULL,
    usuario_id INTEGER NOT NULL,
    especialidad_id INTEGER,
    cedula_profesional VARCHAR(50),
    años_experiencia INTEGER,
    activo BOOLEAN,
    CONSTRAINT doctores_pkey PRIMARY KEY (id),
    CONSTRAINT doctores_usuario_id_key UNIQUE (usuario_id),
    CONSTRAINT doctores_cedula_profesional_key UNIQUE (cedula_profesional),
    CONSTRAINT doctores_usuario_id_fkey FOREIGN KEY (usuario_id) REFERENCES usuarios(id) ON DELETE CASCADE
);

CREATE TABLE pacientes (
    id INTEGER DEFAULT nextval('pacientes_id_seq'::regclass) NOT NULL,
    usuario_id INTEGER NOT NULL,
    fecha_nacimiento DATE,
    genero VARCHAR(20),
    direccion TEXT,
    alergias TEXT,
    activo BOOLEAN,
    CONSTRAINT pacientes_pkey PRIMARY KEY (id),
    CONSTRAINT pacientes_usuario_id_key UNIQUE (usuario_id),
    CONSTRAINT pacientes_usuario_id_fkey FOREIGN KEY (usuario_id) REFERENCES usuarios(id) ON DELETE CASCADE
);

CREATE TABLE intentos_autenticacion_facial (
    id BIGINT DEFAULT nextval('intentos_autenticacion_facial_id_seq'::regclass) NOT NULL,
    sesion_id BIGINT NOT NULL,
    usuario_id INTEGER,
    exito BOOLEAN NOT NULL,
    distancia_coincidencia NUMERIC,
    motivo_fallo VARCHAR(255),
    cantidad_frames INTEGER,
    challenge_validado BOOLEAN,
    liveness_validado BOOLEAN,
    fecha_intento TIMESTAMP DEFAULT now(),
    CONSTRAINT intentos_autenticacion_facial_pkey PRIMARY KEY (id),
    CONSTRAINT intentos_autenticacion_facial_sesion_id_fkey FOREIGN KEY (sesion_id) REFERENCES sesiones_autenticacion_facial(id) ON DELETE CASCADE,
    CONSTRAINT intentos_autenticacion_facial_usuario_id_fkey FOREIGN KEY (usuario_id) REFERENCES usuarios(id) ON DELETE SET NULL
);

CREATE TABLE frames_autenticacion_facial (
    id BIGINT DEFAULT nextval('frames_autenticacion_facial_id_seq'::regclass) NOT NULL,
    sesion_id BIGINT NOT NULL,
    numero_frame INTEGER NOT NULL,
    timestamp_cliente BIGINT,
    rostro_detectado BOOLEAN,
    cantidad_rostros INTEGER,
    calidad_frame NUMERIC,
    ruta_imagen_temporal VARCHAR(255),
    fecha_registro TIMESTAMP DEFAULT now(),
    CONSTRAINT frames_autenticacion_facial_pkey PRIMARY KEY (id),
    CONSTRAINT frames_autenticacion_facial_sesion_id_fkey FOREIGN KEY (sesion_id) REFERENCES sesiones_autenticacion_facial(id) ON DELETE CASCADE
);

